frappe.ui.form.on('Maintenance Item', {
	create_barcode_automatically(frm) {
		if(frm.doc.create_barcode_automatically== 1){
		    frm.set_df_property("barcode","reqd",0)
		    frm.set_value("barcode","")
		}else{
		    frm.set_df_property("barcode","reqd",1)
		}
	}
})

frappe.ui.form.on('Maintenance Order', {
    refresh: function(frm) {
        // Check if user has Operations Officer role but NOT financial roles
        const is_operations = frappe.user.has_role('Operations Officer');
        const has_financial_access = frappe.user.has_role(['Accounts User', 'Accounts Manager', 'Administrator']);

        if (is_operations && !has_financial_access) {
            // Hide financial summary fields
            hide_financial_fields(frm);

            // Hide price columns in child tables
            hide_table_financial_columns(frm);

            // Show informative message
            frm.dashboard.set_headline(
                '<div class="indicator-pill yellow">' +
                '<span class="indicator yellow"></span> ' +
                'Financial details are hidden for Operations team</div>'
            );
        }
    }
});

function hide_financial_fields(frm) {
    // Main financial fields
    const financial_fields = [
        'total_amount',
        'net_total', 
        'total',
        'service_total',
        'advance_paid',
        'outstanding_amount',
        'total_taxes_and_charges',
        'total_quantity',
        'net_quantity',
        'grand_total',
        'rounded_total'
    ];

    financial_fields.forEach(field => {
        frm.toggle_display(field, false);
    });

    // Hide entire sections
    frm.toggle_display('section_break_48', false);
    frm.toggle_display('taxes_and_charges_section', false);
}

function hide_table_financial_columns(frm) {
    // Hide price in Maintenance Service table (table_60 = Maintenance Order Items)
    if (frm.fields_dict.table_60 && frm.fields_dict.table_60.grid) {
        // Method 1: Hide via docfield property
        frm.fields_dict.table_60.grid.update_docfield_property('price', 'hidden', 1);
        frm.fields_dict.table_60.grid.update_docfield_property('price', 'in_list_view', 0);

        // Method 2: Hide via CSS (more forceful)
        setTimeout(() => {
            frm.fields_dict.table_60.grid.grid_rows.forEach(row => {
                if (row.columns_list) {
                    row.columns_list.forEach(col => {
                        if (col.df && col.df.fieldname === 'price') {
                            col.toggle(false);
                        }
                    });
                }
            });
            frm.fields_dict.table_60.grid.refresh();
        }, 100);
    }

    // Hide rate and amount in Spare Parts table (table_66 = Maintenance Order Spare Parts)
    if (frm.fields_dict.table_66 && frm.fields_dict.table_66.grid) {
        // Method 1: Hide via docfield property
        frm.fields_dict.table_66.grid.update_docfield_property('rate', 'hidden', 1);
        frm.fields_dict.table_66.grid.update_docfield_property('amount', 'hidden', 1);
        frm.fields_dict.table_66.grid.update_docfield_property('rate', 'in_list_view', 0);
        frm.fields_dict.table_66.grid.update_docfield_property('amount', 'in_list_view', 0);

        // Method 2: Hide via CSS (more forceful)
        setTimeout(() => {
            frm.fields_dict.table_66.grid.grid_rows.forEach(row => {
                if (row.columns_list) {
                    row.columns_list.forEach(col => {
                        if (col.df && (col.df.fieldname === 'rate' || col.df.fieldname === 'amount')) {
                            col.toggle(false);
                        }
                    });
                }
            });
            frm.fields_dict.table_66.grid.refresh();
        }, 100);
    }
}

// Also hide when rows are added or edited
frappe.ui.form.on('Maintenance Order Items', {
    form_render: function(frm, cdt, cdn) {
        const is_operations = frappe.user.has_role('Operations Officer');
        const has_financial_access = frappe.user.has_role(['Accounts User', 'Accounts Manager', 'Administrator']);

        if (is_operations && !has_financial_access) {
            hide_table_financial_columns(frm);
        }
    }
});

frappe.ui.form.on('Maintenance Order Spare Parts', {
    form_render: function(frm, cdt, cdn) {
        const is_operations = frappe.user.has_role('Operations Officer');
        const has_financial_access = frappe.user.has_role(['Accounts User', 'Accounts Manager', 'Administrator']);

        if (is_operations && !has_financial_access) {
            hide_table_financial_columns(frm);
        }
    }
});
